const income_total = Number($('Get Confirmed Income Total').all()[0].json.income_total || 0);
const fixed_total = Number($('Get True Fixed Total').all()[0].json.fixed_total || 0);

const savings_10pct = income_total * 0.10;
const slush_5pct = income_total * 0.05;
const remainder = income_total - savings_10pct - slush_5pct - fixed_total;

const today = new Date();
const year = today.getFullYear();
const monthIdx = today.getMonth();
const daysInMonth = new Date(year, monthIdx + 1, 0).getDate();
const totalWeeks = Math.ceil(daysInMonth / 7);
const currentWeekNumber = Math.ceil(today.getDate() / 7);
const weeksLeft = Math.max(totalWeeks - currentWeekNumber + 1, 1);

const weeklyGross = remainder / weeksLeft;
const weekendBudget = weeklyGross * 0.20;
const weekdayBudget = weeklyGross - weekendBudget;

const monthDate = `${year}-${String(monthIdx + 1).padStart(2, '0')}-01`;

const items = [];
for (let w = currentWeekNumber; w <= totalWeeks; w++) {
  items.push({
    json: {
      month: monthDate,
      income_total,
      savings_10pct: Number(savings_10pct.toFixed(2)),
      slush_5pct: Number(slush_5pct.toFixed(2)),
      weekly_budget: Number(weekdayBudget.toFixed(2)),
      weekend_budget: Number(weekendBudget.toFixed(2)),
      week_number: w,
    },
  });
}
return items;

const rows = $input.all().map(i => i.json);
const first = $('Compute Budget Weeks').all()[0].json;
const lines = [
  'Weekly budget recalculated.',
  `Income this month: R${first.income_total}`,
  `Savings (10%): R${first.savings_10pct}  |  Slush (5%): R${first.slush_5pct}`,
  '',
];
for (const r of rows) {
  lines.push(`Week ${r.week_number}: weekday R${r.weekly_budget}, weekend R${r.weekend_budget}`);
}
return [{ json: { message: lines.join('\n') } }];
